DOM.loginForm.addEventListener('submit', (e) => {
    e.preventDefault();
    if (DOM.loginPassword.value.trim() === ACCESS_CODE) {
        DOM.loginError.style.display = 'none';
        DOM.loginScreen.style.display = 'none';
        const loadingScreen = document.getElementById('loadingScreen');
        const barFill = document.getElementById('loadingBarFill');
        loadingScreen.style.display = 'flex';
        barFill.style.width = '0%';
        const DURATION = 4000, TICK = 40, STEPS = DURATION / TICK;
        let step = 0;
        const timer = setInterval(() => {
            step++;
            const pct = Math.min(100, Math.round((1 - Math.pow(1 - step/STEPS, 2.5)) * 100));
            barFill.style.width = pct + '%';
            if (step >= STEPS) {
                clearInterval(timer);
                loadingScreen.classList.add('fade-out');
                setTimeout(() => {
                    loadingScreen.style.display = 'none';
                    loadingScreen.classList.remove('fade-out');
                    barFill.style.width = '0%';
                    DOM.appContainer.style.display = 'flex';
                    showToast('Welcome to LASA CHOCOLATES! 🍫', 'success');
                }, 500);
            }
        }, TICK);
    } else {
        DOM.loginError.style.display = 'flex';
        DOM.loginPassword.value = '';
        DOM.loginPassword.focus();
    }
});
